import socket
import json
import time
import threading
from dataclasses import dataclass, asdict
from typing import List, Dict, Any
import struct
import hashlib
import secrets

@dataclass
class Player:
    name: str
    score: int
    ping: int
    team: str

@dataclass
class GameState:
    map_name: str
    game_mode: str
    max_players: int
    time_remaining: int
    round_number: int

class GameServer:
    MAX_PACKET_SIZE = 1400
    MAX_RESPONSE_SIZE = 65000
    RATE_LIMIT_WINDOW = 1.0
    MAX_REQUESTS_PER_WINDOW = 10
    CHALLENGE_TIMEOUT = 30
    
    def __init__(self, host: str = '0.0.0.0', port: int = 27015):
        self.host = host
        self.port = port
        self.socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.running = False
        
        self.players: List[Player] = []
        self.game_state = GameState(
            map_name="de_dust2",
            game_mode="competitive",
            max_players=10,
            time_remaining=300,
            round_number=5
        )
        
        self.rate_limit_tracker: Dict[str, List[float]] = {}
        self.challenges: Dict[str, tuple] = {}
        self.lock = threading.Lock()
        
        self._init_demo_data()
    
    def _init_demo_data(self):
        demo_players = [
            Player("Player1", 1500, 45, "CT"),
            Player("Player2", 1200, 52, "T"),
            Player("Player3", 1800, 38, "CT"),
            Player("Player4", 900, 67, "T"),
            Player("Player5", 2100, 29, "CT"),
        ]
        self.players = demo_players
    
    def _generate_challenge(self) -> bytes:
        return secrets.token_bytes(16)
    
    def _verify_challenge(self, addr: str, challenge: bytes) -> bool:
        with self.lock:
            if addr not in self.challenges:
                return False
            stored_challenge, timestamp = self.challenges[addr]
            if time.time() - timestamp > self.CHALLENGE_TIMEOUT:
                del self.challenges[addr]
                return False
            if stored_challenge == challenge:
                del self.challenges[addr]
                return True
            return False
    
    def _check_rate_limit(self, addr: str) -> bool:
        current_time = time.time()
        
        with self.lock:
            if addr not in self.rate_limit_tracker:
                self.rate_limit_tracker[addr] = []
            
            requests = self.rate_limit_tracker[addr]
            requests = [t for t in requests if current_time - t < self.RATE_LIMIT_WINDOW]
            
            if len(requests) >= self.MAX_REQUESTS_PER_WINDOW:
                return False
            
            requests.append(current_time)
            self.rate_limit_tracker[addr] = requests
            return True
    
    def _cleanup_old_data(self):
        current_time = time.time()
        with self.lock:
            for addr in list(self.rate_limit_tracker.keys()):
                requests = [t for t in self.rate_limit_tracker[addr] 
                           if current_time - t < self.RATE_LIMIT_WINDOW]
                if not requests:
                    del self.rate_limit_tracker[addr]
                else:
                    self.rate_limit_tracker[addr] = requests
            
            for addr in list(self.challenges.keys()):
                _, timestamp = self.challenges[addr]
                if current_time - timestamp > self.CHALLENGE_TIMEOUT:
                    del self.challenges[addr]
    
    def _create_status_response(self) -> Dict[str, Any]:
        return {
            'server_name': 'Secure Game Server',
            'game_state': asdict(self.game_state),
            'players': [asdict(p) for p in self.players],
            'current_players': len(self.players),
            'timestamp': int(time.time())
        }
    
    def _fragment_response(self, data: bytes) -> List[bytes]:
        if len(data) <= self.MAX_PACKET_SIZE:
            return [b'\x00' + data]
        
        fragments = []
        fragment_id = secrets.token_bytes(4)
        total_fragments = (len(data) + self.MAX_PACKET_SIZE - 1) // self.MAX_PACKET_SIZE
        
        if total_fragments > 255:
            total_fragments = 255
        
        for i in range(total_fragments):
            start = i * self.MAX_PACKET_SIZE
            end = min(start + self.MAX_PACKET_SIZE, len(data))
            fragment_data = data[start:end]
            
            header = struct.pack('!B4sBB', 0xFF, fragment_id, i, total_fragments)
            fragments.append(header + fragment_data)
        
        return fragments
    
    def _handle_request(self, data: bytes, addr: tuple):
        try:
            if len(data) < 1:
                return
            
            command = data[0:1]
            
            if command == b'\x01':
                if not self._check_rate_limit(addr[0]):
                    return
                
                challenge = self._generate_challenge()
                with self.lock:
                    self.challenges[addr[0]] = (challenge, time.time())
                
                response = b'\x02' + challenge
                self.socket.sendto(response, addr)
            
            elif command == b'\x03':
                if len(data) < 17:
                    return
                
                challenge = data[1:17]
                
                if not self._verify_challenge(addr[0], challenge):
                    return
                
                if not self._check_rate_limit(addr[0]):
                    return
                
                status_data = self._create_status_response()
                json_data = json.dumps(status_data, separators=(',', ':')).encode('utf-8')
                
                if len(json_data) > self.MAX_RESPONSE_SIZE:
                    json_data = json_data[:self.MAX_RESPONSE_SIZE]
                
                fragments = self._fragment_response(json_data)
                
                for fragment in fragments:
                    self.socket.sendto(fragment, addr)
                    time.sleep(0.001)
            
        except Exception as e:
            print(f"Error handling request from {addr}: {e}")
    
    def start(self):
        self.socket.bind((self.host, self.port))
        self.running = True
        print(f"Game server listening on {self.host}:{self.port}")
        
        cleanup_thread = threading.Thread(target=self._cleanup_loop, daemon=True)
        cleanup_thread.start()
        
        while self.running:
            try:
                self.socket.settimeout(1.0)
                data, addr = self.socket.recvfrom(4096)
                
                handler_thread = threading.Thread(
                    target=self._handle_request,
                    args=(data, addr),
                    daemon=True
                )
                handler_thread.start()
                
            except socket.timeout:
                continue
            except Exception as e:
                if self.running:
                    print(f"Error receiving data: {e}")
    
    def _cleanup_loop(self):
        while self.running:
            time.sleep(5)
            self._cleanup_old_data()
    
    def stop(self):
        self.running = False
        self.socket.close()
        print("Game server stopped")

